<?php
 namespace League\CommonMark\Inline\Parser; use League\CommonMark\Cursor; use League\CommonMark\Delimiter\DelimiterInterface; use League\CommonMark\EnvironmentAwareInterface; use League\CommonMark\EnvironmentInterface; use League\CommonMark\Extension\Mention\Mention; use League\CommonMark\Inline\AdjacentTextMerger; use League\CommonMark\Inline\Element\AbstractWebResource; use League\CommonMark\Inline\Element\Image; use League\CommonMark\Inline\Element\Link; use League\CommonMark\Inline\Element\Text; use League\CommonMark\InlineParserContext; use League\CommonMark\Reference\ReferenceInterface; use League\CommonMark\Reference\ReferenceMapInterface; use League\CommonMark\Util\LinkParserHelper; use League\CommonMark\Util\RegexHelper; final class CloseBracketParser implements InlineParserInterface, EnvironmentAwareInterface { private $environment; public function getCharacters(): array { return [']']; } public function parse(InlineParserContext $inlineContext): bool { $opener = $inlineContext->getDelimiterStack()->searchByCharacter(['[', '!']); if ($opener === null) { return false; } if (!$opener->isActive()) { $inlineContext->getDelimiterStack()->removeDelimiter($opener); return false; } $cursor = $inlineContext->getCursor(); $startPos = $cursor->getPosition(); $previousState = $cursor->saveState(); $cursor->advanceBy(1); if (!($link = $this->tryParseLink($cursor, $inlineContext->getReferenceMap(), $opener, $startPos))) { $inlineContext->getDelimiterStack()->removeDelimiter($opener); $cursor->restoreState($previousState); return false; } $isImage = $opener->getChar() === '!'; $inline = $this->createInline($link['url'], $link['title'], $isImage); $opener->getInlineNode()->replaceWith($inline); while (($label = $inline->next()) !== null) { if ($label instanceof Mention) { $label->replaceWith($replacement = new Text($label->getSymbol() . $label->getIdentifier())); $label = $replacement; } $inline->appendChild($label); } $delimiterStack = $inlineContext->getDelimiterStack(); $stackBottom = $opener->getPrevious(); $delimiterStack->processDelimiters($stackBottom, $this->environment->getDelimiterProcessors()); $delimiterStack->removeAll($stackBottom); AdjacentTextMerger::mergeChildNodes($inline); if (!$isImage) { $inlineContext->getDelimiterStack()->removeEarlierMatches('['); } return true; } public function setEnvironment(EnvironmentInterface $environment) { $this->environment = $environment; } private function tryParseLink(Cursor $cursor, ReferenceMapInterface $referenceMap, DelimiterInterface $opener, int $startPos) { if ($result = $this->tryParseInlineLinkAndTitle($cursor)) { return $result; } if ($link = $this->tryParseReference($cursor, $referenceMap, $opener, $startPos)) { return ['url' => $link->getDestination(), 'title' => $link->getTitle()]; } return false; } private function tryParseInlineLinkAndTitle(Cursor $cursor) { if ($cursor->getCharacter() !== '(') { return false; } $previousState = $cursor->saveState(); $cursor->advanceBy(1); $cursor->advanceToNextNonSpaceOrNewline(); if (($dest = LinkParserHelper::parseLinkDestination($cursor)) === null) { $cursor->restoreState($previousState); return false; } $cursor->advanceToNextNonSpaceOrNewline(); $title = ''; if (\preg_match(RegexHelper::REGEX_WHITESPACE_CHAR, $cursor->peek(-1))) { $title = LinkParserHelper::parseLinkTitle($cursor) ?? ''; } $cursor->advanceToNextNonSpaceOrNewline(); if ($cursor->getCharacter() !== ')') { $cursor->restoreState($previousState); return false; } $cursor->advanceBy(1); return ['url' => $dest, 'title' => $title]; } private function tryParseReference(Cursor $cursor, ReferenceMapInterface $referenceMap, DelimiterInterface $opener, int $startPos): ?ReferenceInterface { if ($opener->getIndex() === null) { return null; } $savePos = $cursor->saveState(); $beforeLabel = $cursor->getPosition(); $n = LinkParserHelper::parseLinkLabel($cursor); if ($n === 0 || $n === 2) { $start = $opener->getIndex(); $length = $startPos - $opener->getIndex(); } else { $start = $beforeLabel + 1; $length = $n - 2; } $referenceLabel = $cursor->getSubstring($start, $length); if ($n === 0) { $cursor->restoreState($savePos); } return $referenceMap->getReference($referenceLabel); } private function createInline(string $url, string $title, bool $isImage): AbstractWebResource { if ($isImage) { return new Image($url, null, $title); } return new Link($url, null, $title); } } 